"""matplotlib.projections.polar — polar projection stubs."""

from matplotlib.axes._axes import Axes
import numpy as _np


class PolarAxes(Axes):
    name = 'polar'

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._theta_offset = 0
        self._theta_direction = 1
        self._r_label_position = 22.5

    def set_theta_offset(self, offset): self._theta_offset = offset
    def get_theta_offset(self): return self._theta_offset
    def set_theta_direction(self, direction): self._theta_direction = direction
    def get_theta_direction(self): return self._theta_direction
    def set_thetalim(self, *args, **kwargs): pass
    def set_thetagrids(self, angles, labels=None, **kwargs): pass
    def set_rgrids(self, radii, labels=None, **kwargs): pass
    def set_rlabel_position(self, value): self._r_label_position = value
    def set_rlim(self, *args, **kwargs): pass
    def get_rlim(self): return (0, 1)
    def set_rmax(self, rmax): pass
    def get_rmax(self): return 1
    def set_rmin(self, rmin): pass
    def get_rmin(self): return 0
    def set_rticks(self, ticks): pass
    def set_thetamin(self, thetamin): pass
    def set_thetamax(self, thetamax): pass


class PolarTransform:
    pass


class InvertedPolarTransform:
    pass
